package form;
import controller.LaporanController;import util.UIUtils;import com.github.lgooddatepicker.components.DatePicker;import javax.swing.*;import javax.swing.table.DefaultTableModel;import java.awt.*;import java.io.File;import java.time.LocalDate;import java.util.*;
public class LaporanForm extends JPanel{LaporanController c=new LaporanController();DefaultTableModel m=new DefaultTableModel(new String[]{"Tanggal","Keterangan","Debit","Kredit"},0);java.util.List<Object[]> rows=new ArrayList<>();public LaporanForm(){setLayout(new BorderLayout());JPanel p=UIUtils.page("Laporan & Analitik");DatePicker a=new DatePicker(),b=new DatePicker();a.setDate(LocalDate.now().minusMonths(1));b.setDate(LocalDate.now());JTextField bulan=UIUtils.textField(3),tahun=UIUtils.textField(4);JButton kas=UIUtils.button("Buku Kas Umum",UIUtils.BLUE),tung=UIUtils.button("Rekap Tunggakan SPP",UIUtils.RED),pdf=UIUtils.button("Export PDF",UIUtils.ORANGE),xls=UIUtils.button("Export Excel",UIUtils.GREEN);kas.addActionListener(e->{try{rows=c.bukuKas(a.getDate(),b.getDate());fill(new String[]{"Tanggal","Keterangan","Debit","Kredit"});}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});tung.addActionListener(e->{try{rows=c.tunggakanSpp(Integer.parseInt(bulan.getText()),Integer.parseInt(tahun.getText()));fill(new String[]{"NIS","Nama","Kelas","Nominal"});}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});pdf.addActionListener(e->{try{c.exportPdf(new File("laporan-skm.pdf"),rows,"Laporan SKM");JOptionPane.showMessageDialog(this,"PDF dibuat");}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});xls.addActionListener(e->{try{c.exportExcel(new File("laporan-skm.xlsx"),rows,"Laporan");JOptionPane.showMessageDialog(this,"Excel dibuat");}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});p.add(UIUtils.toolbar(UIUtils.formLabel("Dari"),a,UIUtils.formLabel("Sampai"),b,UIUtils.formLabel("Bulan"),bulan,UIUtils.formLabel("Tahun"),tahun,kas,tung,pdf,xls),BorderLayout.NORTH);p.add(UIUtils.tableScroll(new JTable(m)));add(p);}void fill(String[] cols){m.setColumnIdentifiers(cols);m.setRowCount(0);for(Object[] r:rows)m.addRow(r);}}
